def prime_fib(n: int):
    """
    This function generates the first n prime Fibonacci numbers.

    Args:
    n (int): The number of prime Fibonacci numbers to generate.

    Returns:
    list: A list of the first n prime Fibonacci numbers.
    """
    def is_prime(num: int) -> bool:
        """Check if a number is prime."""
        if num < 2:
            return False
        for i in range(2, int(num ** 0.5) + 1):
            if num % i == 0:
                return False
        return True

    def fibonacci(n: int) -> int:
        """Generate the nth Fibonacci number."""
        if n <= 0:
            return 0
        elif n == 1:
            return 1
        else:
            a, b = 0, 1
            for _ in range(2, n + 1):
                a, b = b, a + b
            return b

    prime_fibs = []
    i = 1
    while len(prime_fibs) < n:
        fib_num = fibonacci(i)
        if is_prime(fib_num):
            prime_fibs.append(fib_num)
        i += 1
    return prime_fibs
