def string_sequence(n: int) -> str:
    """
    Returns a string of the first n numbers in a sequence where each number is the sum of the two preceding numbers.
    The sequence starts with 0 and 1.

    Args:
        n (int): The number of terms in the sequence.

    Returns:
        str: A string representation of the sequence.
    """
    if n <= 0:
        return ""
    elif n == 1:
        return "0"
    elif n == 2:
        return "0 1"
    else:
        sequence = [0, 1]
        while len(sequence) < n:
            sequence.append(sequence[-1] + sequence[-2])
        return " ".join(map(str, sequence))
