def correct_bracketing(brackets: str):
    """
    This function checks if the input string of brackets is correctly bracketed.
    A string of brackets is correctly bracketed if every opening bracket has a corresponding closing bracket and vice versa.
    The function returns True if the string is correctly bracketed and False otherwise.

    :param brackets: A string of brackets
    :return: A boolean indicating whether the string is correctly bracketed
    """
    stack = []
    bracket_map = {")": "(", "}": "{", "]": "["}
    for bracket in brackets:
        if bracket in bracket_map.values():
            stack.append(bracket)
        elif bracket in bracket_map.keys():
            if not stack or stack.pop() != bracket_map[bracket]:
                return False
    return not stack
```

